using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Chat client via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tool: Note-taking ---
var notes = new List<string>();

[Description("Save a research note. Use this to record important findings during research.")]
string SaveNote([Description("The note text to save")] string note)
{
    notes.Add(note);
    return $"Note saved ({notes.Count} total).";
}

[Description("Retrieve all saved research notes.")]
string GetNotes()
{
    if (notes.Count == 0)
        return "No notes saved yet.";

    return string.Join("\n", notes.Select((n, i) => $"{i + 1}. {n}"));
}

// --- Tool: Web search (simulated) ---
[Description("Search the web for information on a given query. Returns relevant search results.")]
string WebSearch([Description("The search query")] string query)
{
    // In production, replace with a real search API (Bing, Google, etc.)
    // This simulation returns plausible results based on the query.
    return $"""
        Search results for: "{query}"

        1. [Wikipedia] Overview article covering key aspects of {query}.
           Summary: {query} is a broad topic with multiple facets including history,
           current developments, and future outlook.

        2. [Research Paper] Recent academic findings related to {query}.
           Summary: Studies show significant progress in understanding {query},
           with new methodologies yielding promising results.

        3. [News Article] Latest developments in {query} (2025).
           Summary: Industry experts report growing interest in {query},
           with major organizations investing in related initiatives.

        4. [Technical Blog] Practical guide to {query}.
           Summary: A hands-on exploration of {query} covering fundamentals,
           best practices, and common pitfalls to avoid.
        """;
}

// --- Create the agent ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearch),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetNotes),
};

var agent = chatClient.AsAIAgent(
    instructions: """
        You are a research agent. Your job is to research a topic thoroughly by:
        1. Searching the web for relevant information using the WebSearch tool.
        2. Taking notes on key findings using the SaveNote tool.
        3. Performing multiple searches to cover different aspects of the topic.
        4. Finally, retrieving your notes with GetNotes and providing a comprehensive summary.

        Always search at least 2-3 different angles of the topic before summarizing.
        Save important facts as notes as you discover them.
        End with a well-structured summary of your research findings.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// --- Run the agent ---
Console.WriteLine("=== Research Agent ===");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");
Console.WriteLine("─────────────────────────────────────");

var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    },
};

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions);

Console.WriteLine("\n─────────────────────────────────────");
Console.WriteLine("RESEARCH SUMMARY:");
Console.WriteLine("─────────────────────────────────────\n");
Console.WriteLine(response.Message?.Text ?? "No response generated.");
Console.WriteLine("\n─────────────────────────────────────");
Console.WriteLine($"Notes collected: {notes.Count}");

